// ── PINNED TICKETS ────────────────────────────────────────────────────────────
const PINNED_KEY = 'jd_pinned_tickets';

function loadPinned(){ try{ return JSON.parse(localStorage.getItem(PINNED_KEY)||'[]'); }catch(e){ console.error('[Pinned] loadPinned error:',e); return []; } }
function savePinned(list){ try{ localStorage.setItem(PINNED_KEY, JSON.stringify(list)); }catch(e){ console.error('[Pinned] savePinned error:',e); } }

async function addPinnedTicket(){
  const input = document.getElementById('pinnedInput');
  const btn   = document.getElementById('pinnedAddBtn');
  const raw   = (input?.value||'').trim().toUpperCase();
  if(!raw){ toast('info','Please enter a ticket key e.g. LEG-1234'); return; }
  if(!/^[A-Z]+-\d+$/.test(raw)){ toast('error','Invalid key format — use e.g. LEG-1234'); return; }

  const pinned = loadPinned();
  if(pinned.find(p=>p.key===raw)){ toast('info',`${raw} is already pinned`); input.value=''; return; }

  btn.disabled=true; btn.textContent='Loading…';
  try{
    const user = getUser();
    if(!user){ toast('error','Please log in first'); btn.disabled=false; btn.textContent='＋ Track'; return; }
    const base = `${CONFIG.API_BASE}/ex/jira/${user.cloudId}`;
    const data = await apiFetch(`${base}/rest/api/3/issue/${raw}?fields=summary,status,assignee,reporter,created`);
    const f    = data.fields||{};
    const ticket = {
      key:      raw,
      url:      `${user.siteUrl}/browse/${raw}`,
      summary:  f.summary||'',
      status:   f.status?.name||'Unknown',
      assignee: f.assignee?.displayName||'Unassigned',
      reporter: f.reporter?.displayName||'Unknown',
      created:  (f.created||'').slice(0,10),
      pinnedAt: new Date().toISOString(),
    };
    pinned.unshift(ticket);
    savePinned(pinned);
    input.value='';
    toast('success',`✓ ${raw} pinned`);
    renderPinned();
  }catch(e){
    console.error('[Pinned] addPinnedTicket error:', e);
    toast('error',`Could not fetch ${raw}: ${e.message}`);
  }
  btn.disabled=false; btn.textContent='＋ Track';
}

function removePinnedTicket(key){
  savePinned(loadPinned().filter(p=>p.key!==key));
  toast('info',`${key} unpinned`);
  renderPinned();
}

async function refreshPinnedTicket(key){
  try{
    const user = getUser();
    if(!user) return;
    const base = `${CONFIG.API_BASE}/ex/jira/${user.cloudId}`;
    const data = await apiFetch(`${base}/rest/api/3/issue/${key}?fields=summary,status,assignee,reporter,created`);
    const f    = data.fields||{};
    const pinned = loadPinned();
    const idx  = pinned.findIndex(p=>p.key===key);
    if(idx>-1){
      pinned[idx] = {...pinned[idx],
        summary:  f.summary||pinned[idx].summary,
        status:   f.status?.name||pinned[idx].status,
        assignee: f.assignee?.displayName||'Unassigned',
      };
      savePinned(pinned);
      renderPinned();
    }
  }catch(e){ console.error('[Pinned] refreshPinnedTicket error:', e); }
}

function renderPinned(){
  const pinned  = loadPinned();
  const body    = document.getElementById('pinnedBody');
  const countEl = document.getElementById('pinnedCount');
  if(!body) return;
  if(countEl) countEl.textContent = pinned.length + ' ticket' + (pinned.length===1?'':'s');

  if(!pinned.length){
    body.innerHTML='<div class="pinned-empty">No pinned tickets yet — paste any Jira key above to track it here.</div>';
    return;
  }

  const thead=`<thead><tr>
    <th style="width:32px"></th>
    <th>Ticket</th><th>Summary</th><th>Status</th><th>Assignee</th><th>Created</th><th>Lead Time</th><th>Action</th>
  </tr></thead>`;

  const rows = pinned.map(p=>{
    const days = calcLT(p.created);
    const sumClean = esc(normU(p.summary).replace(/\[[^\]]+\]\s*/,''));
    const done = isDone(p.status);
    return `<tr class="tracking-row" data-key="${p.key}" onclick="openPanel('${p.key}',event,'tracking')">
      <td onclick="event.stopPropagation()">
        <button class="pinned-remove-btn" title="Unpin ${p.key}" onclick="event.stopPropagation();removePinnedTicket('${p.key}')">✕</button>
      </td>
      <td onclick="event.stopPropagation()"><a class="ticket-key" href="${p.url}" target="_blank">${p.key}</a></td>
      <td><div class="ticket-summary">${sumClean}</div></td>
      <td><span class="sb ${sClass(p.status)}"><span class="sd"></span>${esc(p.status)}</span></td>
      <td><span class="ac">${esc(p.assignee)}</span></td>
      <td><span class="dc">${p.created}</span></td>
      <td><span class="lt ${ltC(days)}">${days}d</span></td>
      <td onclick="event.stopPropagation()">
        ${!done?`<button class="btn-md" onclick="markDonePinned('${p.key}',this)">✓ Mark Done</button>`
               :'<span style="color:var(--green);font-family:DM Mono,monospace;font-size:11px;opacity:.6">✓ done</span>'}
      </td>
    </tr>`;
  }).join('');

  body.innerHTML=`<div class="table-wrap"><table>${thead}<tbody>${rows}</tbody></table></div>`;
}

async function markDonePinned(key, btn){
  btn.disabled=true; btn.innerHTML='<span class="spin">↻</span>';
  toast('info',`Transitioning ${key} to Done…`);
  try{
    await markIssueDone(key);
    const pinned = loadPinned();
    const p = pinned.find(x=>x.key===key);
    if(p){ p.status='Done'; savePinned(pinned); }
    // Also update allData if present
    const ad = allData.find(x=>x.key===key);
    if(ad){ ad.status='Done'; ad.resolutiondate=new Date().toISOString().slice(0,10); }
    toast('success',`✓ ${key} marked as Done`);
    renderPinned();
    renderDashboard(allData);
  }catch(e){
    console.error('[Pinned] markDonePinned error:', e);
    toast('error',`Failed: ${e.message}`);
    btn.disabled=false; btn.innerHTML='✓ Mark Done';
  }
}


// ── THEME TOGGLE ─────────────────────────────────────────────────────────────
const THEME_KEY = 'jd_theme';
function initTheme(){
  const saved = localStorage.getItem(THEME_KEY)||'dark';
  applyTheme(saved);
}
function toggleTheme(){
  const isLight = document.documentElement.classList.contains('light');
  const next = isLight ? 'dark' : 'light';
  localStorage.setItem(THEME_KEY, next);
  applyTheme(next);
}
function applyTheme(mode){
  const html = document.documentElement;
  const btn  = document.getElementById('btnTheme');
  if(mode==='light'){
    html.classList.add('light');
    if(btn){ btn.textContent='🌙 Dark'; }
  } else {
    html.classList.remove('light');
    if(btn){ btn.textContent='☀️ Light'; }
  }
}
