function saveWizAsDraft(){
  if(!wiz.onboardTicketKey){ toast('info','Please create the onboard ticket first'); return; }
  const draft = {
    id:               'draft_'+wiz.onboardTicketKey,
    savedAt:          new Date().toISOString(),
    platform:         wiz.platform,
    clientName:       wiz.clientName,
    legalTicket:      wiz.legalTicket,
    opportunityLink:  wiz.opportunityLink,
    assignee:         wiz.assignee,
    onboardTicketKey: wiz.onboardTicketKey,
    appId:            wiz.appId,
    projectId:        wiz.projectId,
    organizationId:   wiz.organizationId,
    selectedFeatures: wiz.selectedFeatures,
    extraFields:      wiz.extraFields,
    ojmSelectedChannels: wiz.ojmSelectedChannels||[],
    ojmSelectedFeatures: wiz.ojmSelectedFeatures||[],
    featureAssignees:    wiz.featureAssignees||{},
    step:             2,
  };
  const list = loadDrafts().filter(d=>d.id!==draft.id); // replace existing draft for same ticket
  list.unshift(draft);
  saveDrafts(list);
  toast('success', `Draft saved — resuming from Issue Tracking → Onboarding Progress`);
  closeWizard();
  // Switch to Issue Tracking tab so the draft card is immediately visible
  switchTab('tracking');
  renderOnboardingProgress();
  // Scroll to the progress section
  setTimeout(()=>{
    const sec = document.getElementById('obProgressSection');
    if(sec) sec.scrollIntoView({behavior:'smooth', block:'start'});
  }, 150);
}

function resumeDraft(draftId){
  const draft = loadDrafts().find(d=>d.id===draftId);
  if(!draft){ toast('error','Draft not found'); return; }

  // Restore wizard state from draft
  wiz.platform         = draft.platform;
  wiz.clientName       = draft.clientName;
  wiz.legalTicket      = draft.legalTicket;
  wiz.opportunityLink  = draft.opportunityLink;
  wiz.assignee         = draft.assignee;
  wiz.onboardTicketKey = draft.onboardTicketKey;
  wiz.appId            = draft.appId || '';
  wiz.projectId        = draft.projectId || '';
  wiz.organizationId   = draft.organizationId || '';
  wiz.selectedFeatures    = draft.selectedFeatures || {};
  wiz.extraFields         = draft.extraFields || {};
  wiz.ojmSelectedChannels = draft.ojmSelectedChannels || [];
  wiz.ojmSelectedFeatures = draft.ojmSelectedFeatures || [];
  wiz.featureAssignees    = draft.featureAssignees    || {};
  wiz.step                = draft.step || 3;

  document.getElementById('wizOverlay').style.display='flex';
  renderWizStep();
  toast('info', `Resumed: ${draft.clientName} — ${draft.platform}`);
}

function deleteDraft(draftId){
  saveDrafts(loadDrafts().filter(d=>d.id!==draftId));
  renderOnboardingProgress();
  toast('info','Draft deleted');
}

