let wiz = {
  step: 0,          // 0=platform 1=account 2=appid+features 3=review
  platform: null,
  clientName: '',
  legalTicket: '',
  opportunityLink: '',
  assignee: null,           // { accountId, displayName, avatarUrl }
  onboardTicketKey: null,   // set after creating the onboard ticket
  appId: '',                // auto-detected or manually entered
  projectId: '',
  organizationId: '',
  selectedFeatures: {},     // { featureId: true }
  extraFields: {},          // { featureId: { fieldId: value } }
  ojmSelectedChannels: [], // OJM channels selected by user
  ojmSelectedFeatures: [], // OJM features selected by user
  featureAssignees: {},    // { featureId: { accountId, displayName, avatarUrl } } per-feature override
  _addToObId: null,         // when adding features to existing onboarding
};

// ── TEMPLATE ENGINE ───────────────────────────────────────────────────────────
// Replaces {clientName}, {appId}, {projectId}, {organizationId}, {legalTicket},
// {opportunityLink}, {platform}, {productFeedUrl}, {enableFeature}, and all extra fields
function resolveTemplate(str, featureOverrides){
  if(!str||typeof str!=='string') return str;
  // Build {channels} and {features} lists from selected features
  const _cat = wiz.platform && CATALOGS[wiz.platform];
  const _sel = _cat ? _cat.features.filter(f=>wiz.selectedFeatures[f.id]) : [];
  const _channels = _sel.filter(f=>f.category==='Channels').map(f=>f.name);
  const _features = _sel.filter(f=>f.category!=='Channels').map(f=>f.name);

  // Build OJM channels/features strings
  const _ojmChannels = (wiz.ojmSelectedChannels||[]).join(', ') || 'None';
  const _ojmFeatures = (wiz.ojmSelectedFeatures||[]).join(', ') || 'None';

  // Flatten all feature extra fields (smsQuantity, arName, salesforceId, botId, productFeedUrl, etc.)
  const flatExtras = Object.values(wiz.extraFields||{}).reduce((acc,obj)=>({...acc,...obj}),{});

  const vars = {
    clientName:      wiz.clientName     || '',
    appId:           wiz.appId          || '[TBD]',
    projectId:       wiz.projectId      || '[TBD]',
    organizationId:  wiz.organizationId || '[TBD]',
    legalTicket:     wiz.legalTicket    || '',
    opportunityLink: wiz.opportunityLink|| '',
    platform:        wiz.platform       || '',
    // Built lists
    channels:        _channels.length ? _channels.join(', ') : 'None',
    features:        _features.length ? _features.join(', ') : 'None',
    OJMchannels:     _ojmChannels,
    OJMfeatures:     _ojmFeatures,
    // People
    TS:              wiz.assignee?.displayName || '[TBD]',
    // enableFeature resolved per-ticket via featureOverrides param
    enableFeature:   featureOverrides?.enableFeature || '',
    // All extra fields including productFeedUrl, arName, salesforceId, botId, agentStartDate, etc.
    ...flatExtras,
    // featureOverrides take highest priority (per-ticket values)
    ...(featureOverrides||{}),
  };
  return str.replace(/\{(\w+)\}/g, (match, key)=> key in vars ? vars[key] : match);
}

// Recursively resolve templates in an ADF node tree
function resolveAdfTemplates(node, featureOverrides){
  if(!node) return node;
  if(typeof node === 'string') return resolveTemplate(node, featureOverrides);
  if(node.type === 'text' && node.text){
    return {...node, text: resolveTemplate(node.text, featureOverrides)};
  }
  if(node.content){
    return {...node, content: node.content.map(n=>resolveAdfTemplates(n, featureOverrides))};
  }
  return node;
}
