async function createBotBonnieTicket(){
  const clientName = document.getElementById('bbClientName')?.value?.trim();
  const err = document.getElementById('bbErr');
  if(!clientName){ err.textContent='Client name is required'; err.style.display='block'; return; }
  err.style.display='none';
  const btn = document.getElementById('bbCreateBtn');
  if(btn){ btn.disabled=true; btn.textContent='Creating…'; }
  try{
    const user = getUser();
    const base = `${CONFIG.API_BASE}/ex/jira/${user.cloudId}`;
    const sf   = await apiFetch(`${base}/rest/api/3/issue/BBT-7539?fields=issuetype,description,summary,labels,priority`);
    wiz.clientName = clientName;
    wiz.platform   = 'BotBonnie';
    wiz.extraFields= {};
    // Strip localId attrs from cloned ADF
    function stripLocalIds(node){
      if(!node||typeof node!=='object') return node;
      const {attrs,...rest} = node;
      const ca = attrs ? Object.fromEntries(Object.entries(attrs).filter(([k])=>k!=='localId')) : undefined;
      const cleaned = (ca&&Object.keys(ca).length) ? {...rest,attrs:ca} : rest;
      if(cleaned.content) cleaned.content = cleaned.content.map(stripLocalIds);
      return cleaned;
    }
    // Sanitize the cloned ADF — convert taskList/taskItem (checkboxes) to bulletList/listItem
    // since BBT's create API rejects taskList nodes. Also strip localIds and unsupported blocks.
    function sanitizeAdf(node){
      if(!node||typeof node!=='object') return node;
      // Convert checkbox items to regular bullet points
      if(node.type==='taskList'){
        return { type:'bulletList', content:(node.content||[]).map(sanitizeAdf).filter(Boolean) };
      }
      if(node.type==='taskItem'){
        // Prefix with [ ] or [x] to preserve checkbox state visually
        const checked = node.attrs?.state==='DONE';
        const prefix = { type:'text', text:(checked?'[x] ':'[ ] ') };
        const kids   = (node.content||[]).flatMap(c=>c.content||[c]);
        return { type:'listItem', content:[{ type:'paragraph', content:[prefix,...kids.map(sanitizeAdf)] }] };
      }
      // Remove unsupported block types but keep their text content
      if(['inlineCard','blockCard','embedCard'].includes(node.type)){
        const url = node.attrs?.url||'';
        return url ? { type:'text', text:url } : null;
      }
      // Strip localId and other non-standard attrs
      const {attrs,...rest} = node;
      const cleanAttrs = attrs
        ? Object.fromEntries(Object.entries(attrs).filter(([k])=>!['localId','timestamp'].includes(k)))
        : undefined;
      const cleaned = (cleanAttrs&&Object.keys(cleanAttrs).length) ? {...rest,attrs:cleanAttrs} : rest;
      if(cleaned.content) cleaned.content = cleaned.content.map(sanitizeAdf).filter(Boolean);
      return cleaned;
    }

    const bbDesc = sf.fields?.description
      ? { type:'doc', version:1, content:(sf.fields.description.content||[]).map(sanitizeAdf).filter(Boolean) }
      : { type:'doc', version:1, content:[{ type:'paragraph', content:[{ type:'text', text:'BotBonnie onboarding for '+clientName+'. Please refer to BBT-7539 for the full configuration template.' }] }] };
    const payload = {
      fields:{
        project:    { key:'BBT' },
        issuetype:  sf.fields.issuetype?.id ? { id:sf.fields.issuetype.id } : { name:'Service Request' },
        summary:    `[${clientName}] BotBonnie Onboarding`,
        description: bbDesc,
        labels:     [...(sf.fields.labels||[]).filter(l=>typeof l==='string'), 'onboarding-dashboard',
                     `ob-${clientName.toLowerCase().replace(/\s+/g,'-')}`],
      }
    };
    const created = await apiFetch(`${base}/rest/api/3/issue`,{method:'POST',body:JSON.stringify(payload)});
    addOnboarding({
      id:'ob_bb_'+Date.now(), platform:'BotBonnie', clientName,
      onboardTicketKey:created.key, createdAt:new Date().toISOString().slice(0,10),
      appId:'', projectId:'', organizationId:'',
      features:[{ name:'BotBonnie Onboard', featureId:'bb_onboard', ticketKey:created.key,
                  board:'BBT', mode:'manual_clone', manual:true, status:'Backlog' }],
    });
    document.getElementById('bbModal')?.remove();
    switchTab('tracking');
    renderOnboardingProgress();
    toast('success',`✓ Created ${created.key} — BotBonnie onboarding started`);
  }catch(e){
    if(err){ err.textContent='Failed: '+e.message; err.style.display='block'; }
    if(btn){ btn.disabled=false; btn.textContent='Create Onboard Ticket →'; }
  }
}

function openWizard(){
  wiz = { step:0, platform:null, clientName:'', legalTicket:'', opportunityLink:'',
          assignee:null, onboardTicketKey:null,
          appId:'', projectId:'', organizationId:'',
          selectedFeatures:{}, extraFields:{},
          ojmSelectedChannels:[], ojmSelectedFeatures:[], featureAssignees:{}, _addToObId:null };
  document.getElementById('wizOverlay').style.display='flex';
  renderWizStep();
}

function closeWizard(){
  document.getElementById('wizOverlay').style.display='none';
}

function wizOverlayClick(e){
  if(e.target===document.getElementById('wizOverlay')) closeWizard();
}

function setWizProgress(pct){
  document.getElementById('wizProgressBar').style.width=pct+'%';
}

function renderWizStep(){
  const body   = document.getElementById('wizBody');
  const footer = document.getElementById('wizFooter');
  const stepInd= document.getElementById('wizStepInd');
  setWizProgress((wiz.step/(WIZ_STEPS-1))*100);
  stepInd.textContent = `Step ${wiz.step+1} of ${WIZ_STEPS}`;

  switch(wiz.step){
    case 0: renderWizPlatform(body,footer);   break;
    case 1: renderWizAccount(body,footer);    break;  // client name, legal, opportunity → create onboard ticket
    case 2: renderWizAssignTS(body,footer);   break;  // pick TS responsible for this onboarding
    case 3: renderWizAppIds(body,footer);     break;  // IDs from TS
    case 4: renderWizFeatures(body,footer);   break;  // feature selection (with per-feature assignee override)
    case 5: renderWizReview(body,footer);     break;
  }
}

// ── STEP 0: Platform ──────────────────────────────────────────────────────────
function renderWizPlatform(body, footer){
  document.getElementById('wizTitle').textContent = 'New Onboarding';
  body.innerHTML = `
    <p style="font-size:13px;color:var(--muted2);margin-bottom:16px;line-height:1.6">
      Select the platform to onboard. Each platform has its own ticket catalog.
    </p>
    <div class="platform-grid">
      ${PLATFORMS.map(p=>`
        <div class="platform-card ${!p.active?'disabled':''} ${wiz.platform===p.id?'selected':''}"
          onclick="${p.active?`selectPlatform('${p.id}')`:''}" id="pc-${p.id}">
          <div class="pc-icon">
            ${PLATFORM_LOGOS[p.id]
              ? `<img src="${PLATFORM_LOGOS[p.id]}" alt="${p.id}"
                  style="width:90px;max-height:34px;object-fit:contain;
                         mix-blend-mode:screen;opacity:${p.active?'1':'.45'}"/>`
              : (p.icon||'🎯')}
          </div>
          ${!p.active?'<div class="pc-soon">Coming soon</div>':''}
        </div>`).join('')}
    </div>`;
  footer.innerHTML = `
    <span></span>
    <button class="btn-wiz-next" id="wizNextBtn" onclick="wizNext()" ${!wiz.platform?'disabled':''}>
      Next →
    </button>`;
}

function selectPlatform(id){
  const plat = PLATFORMS.find(p=>p.id===id);
  if(plat?.noWizard){
    // BotBonnie-style: close wizard overlay, open quick modal instead
    closeWizard();
    if(id==='BotBonnie') openBotBonnieModal();
    return;
  }
  wiz.platform = id;
  document.querySelectorAll('.platform-card').forEach(c=>c.classList.remove('selected'));
  document.getElementById('pc-'+id)?.classList.add('selected');
  document.getElementById('wizNextBtn').disabled = false;
}

// ── STEP 1: Account details + create onboard ticket ───────────────────────────
// ── FEATURE CATEGORY RENDERER ────────────────────────────────────────────────
// Renders one category group of feature checkboxes with inline extras.
// For 'Segment Agent' category: shows SA guideline + prerequisites.
// For 'OJM' category: shows OJM channel/feature chip pickers.
// ── FEATURE TOGGLE & EXTRA FIELD HELPERS ─────────────────────────────────────
function toggleFeature(id){
  if(wiz.selectedFeatures[id]) delete wiz.selectedFeatures[id];
  else                          wiz.selectedFeatures[id] = true;

  const item = document.getElementById('fi-'+id);
  if(!item) return;
  const sel = !!wiz.selectedFeatures[id];
  item.classList.toggle('selected', sel);

  const cb = item.querySelector('.feat-checkbox');
  if(cb) cb.textContent = sel ? '✓' : '';

  const extra = document.getElementById('fe-'+id);
  if(extra) extra.style.display = sel ? 'flex' : 'none';
}

function setFeatureExtra(featureId, fieldId, value){
  if(!wiz.extraFields[featureId]) wiz.extraFields[featureId] = {};
  wiz.extraFields[featureId][fieldId] = value;
}

function renderFeatCategory(catName, feats){
  const existingOb = wiz._addToObId ? loadOnboardings().find(o=>o.id===wiz._addToObId) : null;

  // SA category: show guideline/prerequisites banner at top
  let catHeader = '';
  if(catName === 'Segment Agent'){
    const gl = CATALOGS['Segment Agent']?.guideline;
    if(gl){
      const pts = [];
      if(gl.url)          pts.push('<a href="'+gl.url+'" target="_blank" style="color:var(--accent);font-family:DM Mono,monospace;font-size:11px">📖 '+esc(gl.label||'View Guideline')+'</a>');
      if(gl.prereqs?.length) pts.push('<ul style="margin:6px 0 0;padding-left:14px;font-family:DM Mono,monospace;font-size:11px;color:var(--muted2)">'+gl.prereqs.map(function(p){ return '<li>'+esc(p)+'</li>'; }).join('')+'</ul>');
      if(pts.length) catHeader = '<div class="wiz-guideline" style="margin-bottom:10px"><h4>📋 PREREQUISITES</h4>'+pts.join('')+'</div>';
    }
  }
  // OJM category: NO catHeader — picker lives inside ojm_feat extra section

  var itemsHtml = feats.map(function(f){
    var alreadyDone = existingOb ? existingOb.features.some(function(ef){ return ef.featureId===f.id; }) : false;
    var sel         = !!wiz.selectedFeatures[f.id];
    var manualBadge = (f.manual||f.mode==='manual_clone')
      ? '<span style="margin-left:5px;font-family:DM Mono,monospace;font-size:9px;padding:1px 5px;border-radius:3px;background:var(--yellow-soft);color:var(--yellow);border:1px solid rgba(251,191,36,.3)">MANUAL</span>' : '';

    // Build extra fields HTML
    var extraHtml = (f.extra||[]).map(function(ex){
      var val = ((wiz.extraFields[f.id]||{})[ex.id]||'');
      var isDate = ex.pattern && ex.pattern.includes('d{4}');
      return '<div><label class="wiz-label">'+esc(ex.label)+'</label>'
        +'<input class="wiz-input" type="'+(ex.type||'text')+'" id="fex-'+f.id+'-'+ex.id+'"'
        +' placeholder="'+esc(ex.placeholder||'')+'"'
        +' value="'+esc(val)+'"'
        +' oninput="setFeatureExtra(\''+f.id+'\',\''+ex.id+'\',this.value)"'
        +(ex.type==='number'?' min="0"':'')
        +(ex.pattern?' pattern="'+esc(ex.pattern)+'"':'')+'/>'
        +(isDate?'<div class="wiz-hint">Format: YYYY-MM-DD (e.g. 2025-01-15)</div>':'')
        +'</div>';
    }).join('');

    // OJM Feature Enablement: inject channels/features picker inside feat-extra
    var ojmPickerHtml = '';
    if(f.id === 'ojm_feat'){
      var ojmCat = CATALOGS.OJM||{};
      var chHtml = (ojmCat.ojmChannels||[]).map(function(ch){
        var isSel = (wiz.ojmSelectedChannels||[]).includes(ch);
        return '<div class="ojm-chip'+(isSel?' sel':'')+'" data-ojmtype="channel" data-ojmval="'+esc(ch)+'" onclick="toggleOjmChip(this.dataset.ojmtype,this.dataset.ojmval)">'+esc(ch)+'</div>';
      }).join('');
      var ftHtml2 = (ojmCat.ojmFeatures||[]).map(function(ft){
        var isSel = (wiz.ojmSelectedFeatures||[]).includes(ft);
        return '<div class="ojm-chip'+(isSel?' sel':'')+'" data-ojmtype="feature" data-ojmval="'+esc(ft)+'" onclick="toggleOjmChip(this.dataset.ojmtype,this.dataset.ojmval)">'+esc(ft)+'</div>';
      }).join('');
      ojmPickerHtml = '<div style="margin-top:10px">'
        +'<p style="font-size:11px;font-weight:700;color:var(--text);margin:0 0 6px">CHANNELS TO ENABLE <span style="color:var(--red)">*</span></p>'
        +'<div class="ojm-picker" id="ojmChannelPicker">'+chHtml+'</div>'
        +'<p style="font-size:11px;font-weight:700;color:var(--text);margin:10px 0 6px">FEATURES TO ENABLE</p>'
        +'<div class="ojm-picker" id="ojmFeaturePicker">'+ftHtml2+'</div>'
        +'</div>';
    }
        // Per-feature assignee override (shown when feature is selected)
    var overrideAsn = (wiz.featureAssignees||{})[f.id];
    var asnOverrideHtml = '<div style="margin-top:10px;padding-top:8px;border-top:1px solid var(--border)">'
      +'<label style="font-family:DM Mono,monospace;font-size:10px;color:var(--muted);display:block;margin-bottom:4px">ASSIGNEE OVERRIDE <span style="color:var(--muted)">(optional — overrides default TS)</span></label>'
      +'<div style="display:flex;align-items:center;gap:8px">'
      +(overrideAsn
        ? '<img src="'+esc(overrideAsn.avatarUrl)+'" style="width:22px;height:22px;border-radius:50%" alt=""/>'
          +'<span style="font-size:12px;color:var(--text)">'+esc(overrideAsn.displayName)+'</span>'
          +'<button onclick="clearFeatAsn(this.dataset.fid)" data-fid="'+f.id+'" style="background:transparent;border:1px solid var(--border);color:var(--muted2);border-radius:5px;padding:2px 8px;font-size:10px;cursor:pointer">✕</button>'
        : '<button class="btn-reassign" style="font-size:11px" data-fid="'+f.id+'" onclick="openFeatAsnPicker(this.dataset.fid,event)">👤 Assign someone specific</button>')
      +'</div>'
      +'<div class="inline-asn-dd" id="featAsn-'+f.id+'" style="display:none;position:fixed;z-index:9999;background:var(--surface2);border:1px solid var(--border);border-radius:8px;box-shadow:0 8px 24px rgba(0,0,0,.4);min-width:260px">'
      +'<input type="text" class="wiz-asn-search" placeholder="Type name to search…" id="featAsnSearch-'+f.id+'" data-fid="'+f.id+'" oninput="searchFeatAsn(this.dataset.fid)" autocomplete="off"/>'
      +'<div id="featAsnList-'+f.id+'" style="max-height:180px;overflow-y:auto"></div>'
      +'</div>'
      +'</div>';

    var hintHtml = '';
    if(f.manual||f.mode==='manual_clone') hintHtml += '<p class="wiz-hint">⚠️ Requires manual update after creation — clone from <a href="https://appier.atlassian.net/browse/'+f.sample+'" target="_blank">'+f.sample+'</a>.</p>';
    if(f.suggestedAssignee)               hintHtml += '<p class="wiz-hint" style="color:var(--accent)">💡 Suggested assignee: <strong>'+esc(f.suggestedAssignee)+'</strong></p>';

    // Use plain string for onclick — no nested backticks
    var clickAction = alreadyDone ? '' : 'toggleFeature(\'' + f.id + '\')';

    return '<div class="feat-item '+(sel?'selected':'')+'" id="fi-'+f.id+'"'+(alreadyDone?' style="opacity:.4;pointer-events:none"':'')+'>'
      +'<div class="feat-row" onclick="'+clickAction+'">'
      +'<div class="feat-checkbox">'+(alreadyDone?'✓':sel?'✓':'')+'</div>'
      +'<span class="feat-name">'+esc(f.name)+manualBadge+'</span>'
      +'<span class="feat-mode-badge">'+(alreadyDone?'✓ created':(f.manual||f.mode==='manual_clone')?'⚠️ manual':'clone')+'</span>'
      +'</div>'
      +'<div class="feat-extra" id="fe-'+f.id+'">'
      +extraHtml+ojmPickerHtml+hintHtml+asnOverrideHtml
      +'</div>'
      +'</div>';
  }).join('');

  return '<div class="feat-category" id="fc-'+catName.replace(/\s+/g,'_')+'">'
    +'<div class="feat-cat-label">'+esc(catName)+'</div>'
    +catHeader
    +'<div class="feat-items">'+itemsHtml+'</div>'
    +'</div>';
}


// ── WIZARD ASSIGNEE DROPDOWN ─────────────────────────────────────────────────
let wizAsnAllUsers = [];

async function toggleWizAsnDropdown(e){
  e.stopPropagation();
  const panel = document.getElementById('wizAsnPanel');
  const btn   = document.getElementById('wizAsnBtn');
  if(!panel||!btn) return;
  const isOpen = panel.classList.toggle('open');
  btn.classList.toggle('open', isOpen);
  if(isOpen){
    const r = btn.getBoundingClientRect();
    const dropH = 280;
    const top = (window.innerHeight - r.bottom > dropH) ? r.bottom + 4 : r.top - dropH - 4;
    panel.style.top   = Math.max(4, top) + 'px';
    panel.style.left  = r.left + 'px';
    panel.style.width = r.width + 'px';
    document.getElementById('wizAsnSearchInput')?.focus();
    if(!wizAsnAllUsers.length) await loadWizAsnUsers();
  }
}

async function loadWizAsnUsers(){
  const list = document.getElementById('wizAsnList');
  if(!list) return;
  list.innerHTML = '<div class="wiz-asn-opt" style="pointer-events:none;color:var(--muted)">Loading…</div>';
  try{
    const user = getUser();
    if(!user) return;
    const base = `${CONFIG.API_BASE}/ex/jira/${user.cloudId}`;
    const data = await apiFetch(`${base}/rest/api/3/user/search?query=.&maxResults=50`);
    wizAsnAllUsers = (data||[]).filter(u=>u.accountType==='atlassian');
    renderWizAsnList('');
  }catch(e){
    const list2 = document.getElementById('wizAsnList');
    if(list2) list2.innerHTML = '<div class="wiz-asn-opt" style="pointer-events:none;color:var(--red)">Error: '+esc(e.message)+'</div>';
  }
}

async function filterWizAsnList(){
  const input = document.getElementById('wizAsnSearchInput');
  const q = input?.value?.trim()||'';
  const list = document.getElementById('wizAsnList');

  // Live server search when user types 2+ chars
  if(q.length >= 2){
    if(list) list.innerHTML='<div class="wiz-asn-opt" style="pointer-events:none;color:var(--muted)">Searching…</div>';
    try{
      const user = getUser();
      const base = `${CONFIG.API_BASE}/ex/jira/${user.cloudId}`;
      const results = await apiFetch(`${base}/rest/api/3/user/search?query=${encodeURIComponent(q)}&maxResults=20`);
      const users = (results||[]).filter(u=>u.accountType==='atlassian');
      if(!list) return;
      if(!users.length){
        list.innerHTML='<div class="wiz-asn-opt" style="pointer-events:none;color:var(--muted)">No users found for "'+esc(q)+'"</div>';
        return;
      }
      list.innerHTML = users.map(u=>`
        <div class="wiz-asn-opt ${wiz.assignee?.accountId===u.accountId?'sel':''}"
          onclick="pickWizAssignee('${esc(u.accountId)}','${esc(u.displayName)}','${esc(u.avatarUrls?.['24x24']||'')}')">
          ${u.avatarUrls?.['24x24']?`<img src="${u.avatarUrls['24x24']}" alt=""/>`:'<span style="display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;border-radius:50%;background:var(--surface);font-size:10px">👤</span>'}
          <span style="flex:1">${esc(u.displayName)}</span>
          <span style="font-size:10px;color:var(--muted)">${esc(u.emailAddress||'')}</span>
        </div>`).join('');
    }catch(e){
      if(list) list.innerHTML='<div class="wiz-asn-opt" style="pointer-events:none;color:var(--red)">Search failed: '+esc(e.message)+'</div>';
    }
  } else {
    // Show cached list for short/empty queries
    renderWizAsnList(q.toLowerCase());
  }
}

function renderWizAsnList(q){
  const list = document.getElementById('wizAsnList');
  if(!list) return;
  const users = q ? wizAsnAllUsers.filter(u=>(u.displayName||'').toLowerCase().includes(q)||(u.emailAddress||'').toLowerCase().includes(q)) : wizAsnAllUsers;
  if(!users.length){ list.innerHTML='<div class="wiz-asn-opt" style="pointer-events:none;color:var(--muted)">No users found</div>'; return; }
  list.innerHTML = users.map(u=>`
    <div class="wiz-asn-opt ${wiz.assignee?.accountId===u.accountId?'sel':''}"
      onclick="pickWizAssignee('${esc(u.accountId)}','${esc(u.displayName)}','${esc(u.avatarUrls?.['24x24']||'')}')">
      ${u.avatarUrls?.['24x24']?`<img src="${u.avatarUrls['24x24']}" alt=""/>`:'<span style="display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;border-radius:50%;background:var(--surface);font-size:10px">👤</span>'}
      <span style="flex:1">${esc(u.displayName)}</span>
      <span style="font-size:10px;color:var(--muted)">${esc(u.emailAddress||'')}</span>
    </div>`).join('');
}

function pickWizAssignee(accountId, displayName, avatarUrl){
  wiz.assignee = { accountId, displayName, avatarUrl };
  document.getElementById('wizAsnPanel')?.classList.remove('open');
  document.getElementById('wizAsnBtn')?.classList.remove('open');
  renderWizStep(); // re-render to update button display
}

function clearWizAssignee(){ wiz.assignee = null; renderWizStep(); }

// Close wizard assignee dropdown on outside click
document.addEventListener('click', e=>{
  const wrap = document.getElementById('wizAsnWrap');
  if(wrap && !wrap.contains(e.target)){
    document.getElementById('wizAsnPanel')?.classList.remove('open');
    document.getElementById('wizAsnBtn')?.classList.remove('open');
  }
});

// ── WIZARD ONBOARD TICKET CREATION ───────────────────────────────────────────
async function wizCreateOnboardTicket(){
  // Pre-populate global extra fields
  if(!wiz.extraFields['_global']) wiz.extraFields['_global']={};
  wiz.extraFields['_global'].legalTicket     = wiz.legalTicket;
  wiz.extraFields['_global'].opportunityLink = wiz.opportunityLink;

  // If already created, just advance to next step
  if(wiz.onboardTicketKey){ wizNext(); return; }

  // Validation is done in wizAccountNext; here we just check TS step's error div
  const err = document.getElementById('wizErr2');
  if(!wiz.clientName||!wiz.legalTicket||!wiz.opportunityLink){
    if(err){err.textContent='Missing account details — please go back and complete step 2';err.style.display='block';}
    return;
  }
  if(err) err.style.display='none';

  const btn = document.getElementById('wizAccBtn');
  if(btn){ btn.disabled=true; btn.textContent='Creating…'; }

  try{
    const user = getUser();
    const base = `${CONFIG.API_BASE}/ex/jira/${user.cloudId}`;
    const cat  = CATALOGS[wiz.platform];
    const boardKey = cat?.board || 'QGWL';

    // Fetch sample onboard ticket
    const f = await apiFetch(`${base}/rest/api/3/issue/${cat.onboardTicket.sampleKey}?fields=issuetype,description,labels,priority`);

    // Build description with template variables
    const desc = [
      'Client: '+wiz.clientName,
      'Platform: '+wiz.platform,
      'Legal Ticket: '+wiz.legalTicket,
      'Opportunity Link: '+wiz.opportunityLink,
      'Assigned TS: '+(wiz.assignee?.displayName||'TBD'),
      '',
      '--- To be filled in by TS ---',
      'App ID: {appId}',
      'Project ID: {projectId}',
      'Organization ID: {organizationId}',
    ].join('\n');

    const payload = {
      fields:{
        project:     { key: boardKey },
        issuetype:   f.fields?.issuetype?.id ? { id: f.fields.issuetype.id } : { name:'Task' },
        summary:     resolveTemplate(`[${wiz.clientName}] ${wiz.platform} Onboarding`),
        description: { type:'doc', version:1, content:[{type:'paragraph',content:[{type:'text',text:desc}]}] },
        labels:      [...(f.fields?.labels||[]).filter(l=>typeof l==='string'), 'onboarding-dashboard'],
        ...(cat?.reporterRequired ? { reporter:{ accountId:user.accountId } } : {}),
        ...(Object.values(CATALOGS).find(c=>c.board===boardKey)?.requiredCustomFields||{}),
      }
    };
    if(wiz.assignee?.accountId) payload.fields.assignee = { accountId: wiz.assignee.accountId };

    const created = await apiFetch(`${base}/rest/api/3/issue`,{method:'POST',body:JSON.stringify(payload)});
    wiz.onboardTicketKey = created.key;
    renderWizStep(); // re-render step 2 (Assign TS) to show success banner + Enter IDs button
    toast('success', `✓ Onboard ticket created: ${created.key}`);
  }catch(e){
    if(err){ err.textContent='Failed: '+e.message; err.style.display='block'; }
    if(btn){ btn.disabled=false; btn.textContent='Create Onboard Ticket →'; }
  }
}

